from flask import Flask, request, render_template_string, redirect, url_for
from flask_mail import Mail, Message
import secrets
import string
import hashlib
import sqlite3
from itsdangerous import URLSafeTimedSerializer
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret_key_here'
app.config['MAIL_SERVER'] = 'smtp.gmail.com'
app.config['MAIL_PORT'] = 587
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USERNAME'] = 'your_email@gmail.com'
app.config['MAIL_PASSWORD'] = 'your_password'

mail = Mail(app)

# Database setup
conn = sqlite3.connect('users.db')
cursor = conn.cursor()

cursor.execute('''
    CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY,
        username TEXT NOT NULL,
        email TEXT NOT NULL UNIQUE,
        password TEXT NOT NULL,
        mfa_enabled INTEGER DEFAULT 0
    )
''')

# Serializer setup
s = URLSafeTimedSerializer(app.config['SECRET_KEY'], salt='mfa-reset-salt', timeout=3600)

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    email = request.form.get('email')
    
    # Validate email
    cursor.execute("SELECT * FROM users WHERE email=?", (email,))
    user = cursor.fetchone()
    
    if not user:
        return 'Email not found', 404
    
    # Generate secret and store it in the database
    secret = ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(16))
    hashed_secret = hashlib.sha256(secret.encode()).hexdigest()
    cursor.execute("UPDATE users SET mfa_secret=? WHERE email=?", (hashed_secret, email))
    
    # Send reset link to the user's email
    msg = Message('Reset MFA Link', sender='your_email@gmail.com', recipients=[email])
    msg.body = render_template_string('''
        <p>Click this link to disable MFA and log in with your password:</p>
        <a href="{{ url_for('reset_mfa_link', secret=secret, _external=True) }}">Reset MFA Link</a>
    ''', url_for='reset_mfa_link', secret=secret)
    mail.send(msg)
    
    return 'MFA reset link sent to your email'

@app.route('/reset-mfa-link/<string:secret>')
def reset_mfa_link(secret):
    # Verify the secret
    hashed_secret = hashlib.sha256(secret.encode()).hexdigest()
    cursor.execute("SELECT * FROM users WHERE mfa_secret=?", (hashed_secret,))
    user = cursor.fetchone()
    
    if not user:
        return 'Invalid secret', 401
    
    # Disable MFA for the user
    cursor.execute("UPDATE users SET mfa_enabled=0, mfa_secret='' WHERE id=?", (user[0],))
    
    return redirect(url_for('login'))

@app.route('/login')
def login():
    if request.method == 'POST':
        email = request.form.get('email')
        password = request.form.get('password')
        
        # Validate user credentials
        cursor.execute("SELECT * FROM users WHERE email=?", (email,))
        user = cursor.fetchone()
        
        if not user or not check_password_hash(user[3], password):
            return 'Invalid username or password', 401
        
        # Check if MFA is enabled for the user
        if user[4] == 1:
            return 'MFA required', 403
        
        # Login successful, redirect to dashboard
        return redirect(url_for('dashboard'))
    
    return render_template_string('<form method="post"><input type="email" name="email"><input type="password" name="password"><button type="submit">Login</button></form>')

